using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" → "$type".
            // Existing documents still use "Discriminator", so keep the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" → "Key".
            // Existing documents use "Blog|<key>", so preserve that format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: EF 9 removed HasIndex for Cosmos (indexes are
            // managed by Cosmos DB itself). The previous HasIndex call is removed.
        });
    }
}

